import{_ as d,o as a,c as r,a2 as e}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"1962年年中信","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1962年/年中信.md","filePath":"01_letters/1962年/年中信.md"}'),h={name:"01_letters/1962年/年中信.md"};function o(p,t,l,n,i,s){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="_1962年年中信" tabindex="-1">1962年年中信 <a class="header-anchor" href="#_1962年年中信" aria-label="Permalink to &quot;1962年年中信&quot;">​</a></h1><p><strong>发件方</strong>：巴菲特合伙有限公司</p><p><strong>地址</strong>：内布拉斯加州奥马哈市基维特广场810号，奥马哈31区</p><p><strong>日期</strong>：1962年7月6日</p><h2 id="一则提醒" tabindex="-1">一则提醒 <a class="header-anchor" href="#一则提醒" aria-label="Permalink to &quot;一则提醒&quot;">​</a></h2><p>在1962年1月24日发布的1961年年度报告中，我写了一个名为“关于未来的预测”的章节。我无意让各位反复阅读枯燥的内容，但完整重印这一章节，或许很有必要：</p><p><strong>关于未来的预测</strong></p><p>老读者们（或许是我自作多情了）看到我要谈预测，可能会觉得我偏离了一贯的风格。预测向来是我极力回避的事情，常规情况下，我现在依然不会去做。</p><p>我绝对不会去预测未来一两年整体商业环境和股票市场的走势，因为我对此一无所知，也永远不会知道。</p><p>但我认为，大家可以完全确定的是，未来十年里，一定会有几年大盘涨幅达到20%或25%，也会有几年大盘跌幅达到同样的幅度，大部分年份的涨幅则会介于两者之间。我不知道这些年份会以怎样的顺序出现，也不认为这对长期投资者而言有什么重要意义。</p><p>拉长周期来看，我认为道指通过股息和股价上涨，大概率能实现年化5%-7%的复利收益。尽管近些年市场表现亮眼，但如果有人指望从大盘中获得远高于这个水平的收益，大概率会失望。</p><p>我们的目标，是持续积累每年相对道指的超额收益，而不用过度在意某一年的绝对收益是正还是负。在我看来，道指下跌25%、我们下跌15%的年份，远比我们和道指都上涨20%的年份要出色得多。我跟合伙人们反复强调过这一点，也看着大家带着不同程度的认同点头。对我而言，最重要的是，各位能完全理解我这一观点背后的逻辑，不仅是理智上认同，更是发自内心地接受。</p><p>基于前文所述的投资模式，我们相对道指表现最好的年份，大概率会出现在下跌或横盘的市场中。因此，我们追求的超额收益，每年的幅度会有极大的波动。一定会有某些年份，我们的业绩跑输道指，但如果拉长周期，我们能实现每年平均跑赢道指10个百分点，我就认为业绩达到了预期。</p><p>具体来说，如果某一年市场下跌35%或40%（我认为未来十年里，有极大的概率会出现这样的年份，只是没人知道是哪一年），我们应该只会下跌15%-20%；如果市场全年基本持平，我们希望能实现10个百分点左右的超额收益；如果市场上涨20%甚至更多，我们会尽力跟上涨幅。</p><p>如果长期能实现这样的业绩表现，意味着当道指实现年化5%-7%的复利收益时，我们有望实现年化15%-17%的收益。</p><p>上述预期听起来或许有些鲁莽，毫无疑问，站在1965年或1970年的视角回头看，这些预期可能会显得格外不切实际，也有可能最终证明我完全错了。但我认为，各位合伙人有权知道我对此的真实想法，即便投资行业的特性，决定了这类预期出现偏差的概率极高。单一年份的业绩波动可能会非常大，1961年就是如此，幸运的是，这次的波动是正向的。但不可能每一年都这么幸运。</p><h2 id="_1962年上半年市场与业绩情况" tabindex="-1">1962年上半年市场与业绩情况 <a class="header-anchor" href="#_1962年上半年市场与业绩情况" aria-label="Permalink to &quot;1962年上半年市场与业绩情况&quot;">​</a></h2><p>1961年末至1962年6月30日，道指从731.14点下跌至561.28点。如果在此期间持有道指成分股，可获得约11美元的股息，因此道指的整体亏损为21.7%。对于关注统计数据的合伙人，附录A列出了自首批合伙基金成立以来，道指的逐年表现。</p><p>正如前文所述，道指下跌的行情，正是我们积累超额收益的窗口期。这些超额收益，叠加我们在上涨市场中仅需达到平均水平的业绩，就能为我们带来非常可观的长期收益。我们的目标是：道指每下跌1%，我们的跌幅仅为0.5%左右。如果能实现这一目标，就意味着我们的股票投资工具，比市场上几乎所有其他投资渠道都要保守得多。</p><p>如附录B所示（包含了前身合伙基金的合并业绩），1962年上半年，我们取得了合伙基金历史上最好的业绩表现之一：向合伙人分配收益前，整体亏损7.5%，而同期道指整体亏损21.7%。如果大盘在下半年继续下跌，这14.2个百分点的超额收益大概率会进一步扩大；如果市场出现反弹，超额收益则可能收窄。</p><p>请各位始终记住我反复强调的一点：不要过度看重半年甚至一年的短期业绩。短期的业绩衡量，会放大投资表现中的偶然波动。尽管当前的市场环境让我们上半年取得了异常出色的业绩，但未来一定会出现我们表现相对糟糕的时期。需要说明的是，本次业绩统计中，我们持有的登普斯特磨坊制造公司的控股权估值未做任何调整，尽管近几个月的公司经营进展显示，其最终变现价值很可能会高于当前估值。</p><h2 id="上半年投资公司的业绩表现" tabindex="-1">上半年投资公司的业绩表现 <a class="header-anchor" href="#上半年投资公司的业绩表现" aria-label="Permalink to &quot;上半年投资公司的业绩表现&quot;">​</a></h2><p>过往的信件中，我一直强调，道指作为投资业绩的标尺，绝非轻易就能战胜的。无论资金是通过投资公司、投资顾问、银行信托部门，还是个人投资者自主操作投入股市，我坚信，绝大多数投资的最终结果都会与道指相近，而且业绩偏离道指时，跑输的概率远大于跑赢的概率。</p><p>为了印证这一点，我们持续将道指、有限合伙人的实际收益，与两只规模最大、专注普通股投资的开放式共同基金，以及两只规模最大的封闭式投资公司做对比。附录C的表格展示了过去五年的业绩，大家会发现，这些基金的业绩与道指极为接近，它们的合计管理规模约35亿美元。</p><p>为了让这封信能尽快发出，我们在封闭式基金的半年业绩数据出炉前就安排了邮寄。但两只开放式共同基金的业绩均跑输了道指：马萨诸塞投资信托整体亏损23%，投资者股票基金整体亏损25.4%。</p><p>这并非个例，1962年6月13日《华尔街日报》的头条文章《基金VS市场》就印证了这一点。该文章研究了17只大型普通股基金，从道指734点的高点到文章发布时，所有基金的业绩都跑输了道指，尽管部分基金的差距很小。</p><p>上半年跌幅最大的，是那些所谓的“成长型”基金，几乎无一例外，它们的跌幅都远大于道指。其中，过去几年业绩最好的三只大型“成长型”基金（现在看来，“成长型”这个标签更像是一种讽刺）——富达资本基金、普特南成长基金、惠灵顿权益基金，上半年平均亏损32.3%。</p><p>公平地说，凭借1959-1961年的出色业绩，它们至今的整体表现依然高于行业平均水平，未来也可能继续保持。但颇具讽刺意味的是，正是早期的优异业绩吸引了大量新投资者涌入，导致今年承受亏损的投资者数量，远多于早年享受优异收益的投资者。</p><p>这一经历印证了我的观点：投资业绩必须通过包含上涨和下跌行情的完整周期来评判。市场永远会有上涨和下跌，这一点，现在的大家或许比六个月前理解得更深刻。</p><p>我列出这些投资公司的业绩，并非因为我们的投资模式与它们相近，也不是因为我们的投资组合与它们相似。而是因为这些基金的业绩，代表了那些拿着高薪、管理着高达200亿美元证券的专业投资管理人的行业平均水平。我相信，这类管理模式，也是规模更大的资金的主流管理方式。我认为，如果不投资我们的合伙基金，很多合伙人的资金大概率会交由这类机构管理，因此这个对比具备参考意义。</p><h2 id="资产价值说明" tabindex="-1">资产价值说明 <a class="header-anchor" href="#资产价值说明" aria-label="Permalink to &quot;资产价值说明&quot;">​</a></h2><p>上述业绩计算，均为扣除普通合伙人业绩分成、合伙人月度赎回款之前的口径。当然，如果全年整体收益未达到市值口径的6%（亏损可结转至后续年度抵扣），普通合伙人将不提取任何业绩分成。</p><p>因此，未赎回资金的合伙人，上半年市值权益缩水7.5%；而按照年化6%的比例按月赎回的合伙人，上半年市值权益缩水10.5%。如果我们全年的业绩低于6%（除非道指出现大幅反弹，否则这种情况极有可能发生），按月赎回的合伙人，在1962年12月31日的市值权益将会出现缩水。这也意味着，明年基于新的市值权益、按照年化6%计算的月度赎回款，也会按比例相应减少。</p><p>举个例子：如果我们全年整体亏损7%，一位1962年1月1日持有10万美元市值权益、按月赎回的合伙人，到1962年12月31日，其权益将变为8.7万美元。其中，7%的亏损导致权益减少7000美元，全年每月500美元的赎回款合计6000美元，两者合计减少1.3万美元。因此，1963年1月1日，其市值权益为8.7万美元，明年的月度赎回款将变为435美元。</p><p>当然，以上说明均不适用于1962年收到的预付投资款，这类资金不参与盈亏分配，仅获得年化6%的固定收益。</p><h3 id="附录a" tabindex="-1">附录A <a class="header-anchor" href="#附录a" aria-label="Permalink to &quot;附录A&quot;">​</a></h3><h4 id="道琼斯工业平均指数表现" tabindex="-1">道琼斯工业平均指数表现 <a class="header-anchor" href="#道琼斯工业平均指数表现" aria-label="Permalink to &quot;道琼斯工业平均指数表现&quot;">​</a></h4><table tabindex="0"><thead><tr><th>时间</th><th>道指收盘点位</th><th>年内涨跌幅</th><th>道指股息</th><th>道指整体收益</th><th>整体收益率</th></tr></thead><tbody><tr><td>1956年</td><td>499.47点</td><td>-</td><td>-</td><td>-</td><td>-</td></tr><tr><td>1957年</td><td>435.69点</td><td>-63.78点</td><td>21.61点</td><td>-42.17点</td><td>-8.4%</td></tr><tr><td>1958年</td><td>583.65点</td><td>147.96点</td><td>20.00点</td><td>167.96点</td><td>38.5%</td></tr><tr><td>1959年</td><td>679.36点</td><td>95.71点</td><td>20.74点</td><td>116.45点</td><td>20.0%</td></tr><tr><td>1960年</td><td>615.89点</td><td>-63.47点</td><td>21.36点</td><td>-42.11点</td><td>-6.2%</td></tr><tr><td>1961年</td><td>731.14点</td><td>115.25点</td><td>22.61点</td><td>137.86点</td><td>22.4%</td></tr><tr><td>1962年6月30日</td><td>561.28点</td><td>-169.86点</td><td>11.00点（预估）</td><td>-158.86点</td><td>-21.7%</td></tr></tbody></table><h3 id="附录b" tabindex="-1">附录B <a class="header-anchor" href="#附录b" aria-label="Permalink to &quot;附录B&quot;">​</a></h3><h4 id="合伙基金业绩表现" tabindex="-1">合伙基金业绩表现 <a class="header-anchor" href="#合伙基金业绩表现" aria-label="Permalink to &quot;合伙基金业绩表现&quot;">​</a></h4><table tabindex="0"><thead><tr><th>时间</th><th>合伙基金整体收益率(1)</th><th>有限合伙人实际收益率(2)</th></tr></thead><tbody><tr><td>1957年</td><td>10.4%</td><td>9.3%</td></tr><tr><td>1958年</td><td>40.9%</td><td>32.2%</td></tr><tr><td>1959年</td><td>25.9%</td><td>20.9%</td></tr><tr><td>1960年</td><td>22.8%</td><td>18.6%</td></tr><tr><td>1961年</td><td>45.9%</td><td>35.9%</td></tr><tr><td>1962年6月30日</td><td>-7.5%</td><td>-7.5%</td></tr><tr><td>(1) 1957-1961年数据为全年持续运营的所有前身有限合伙基金的合并业绩，统计口径为扣除全部运营费用后、向合伙人分配收益及普通合伙人计提业绩报酬前。</td><td></td><td></td></tr></tbody></table><p>(2) 1957-1961年数据基于前一列的合伙基金整体收益率，按照当前合伙协议约定的普通合伙人业绩分配规则模拟计算。</p><h3 id="附录c" tabindex="-1">附录C <a class="header-anchor" href="#附录c" aria-label="Permalink to &quot;附录C&quot;">​</a></h3><h4 id="逐年业绩表现" tabindex="-1">逐年业绩表现 <a class="header-anchor" href="#逐年业绩表现" aria-label="Permalink to &quot;逐年业绩表现&quot;">​</a></h4><table tabindex="0"><thead><tr><th>年份</th><th>马萨诸塞投资信托(1)</th><th>投资者股票基金(1)</th><th>雷曼公司(2)</th><th>大陆三角公司(2)</th></tr></thead><tbody><tr><td>1957年</td><td>-11.4%</td><td>-12.4%</td><td>-11.4%</td><td>-2.4%</td></tr><tr><td>1958年</td><td>42.7%</td><td>47.5%</td><td>40.8%</td><td>33.2%</td></tr><tr><td>1959年</td><td>9.0%</td><td>10.3%</td><td>8.1%</td><td>8.4%</td></tr><tr><td>1960年</td><td>-1.0%</td><td>-0.6%</td><td>2.5%</td><td>2.8%</td></tr><tr><td>1961年</td><td>25.6%</td><td>24.9%</td><td>23.6%</td><td>22.5%</td></tr><tr><td>1962年6月30日</td><td>-23.0%</td><td>-25.4%</td><td>暂无数据</td><td>暂无数据</td></tr><tr><td>(1) 收益根据资产净值变动，加计年内向持有人支付的全部分红计算。</td><td></td><td></td><td></td><td></td></tr></tbody></table><p>(2) 数据来源：1962年《穆迪银行与金融手册》。</p><h4 id="复利累计收益" tabindex="-1">复利累计收益 <a class="header-anchor" href="#复利累计收益" aria-label="Permalink to &quot;复利累计收益&quot;">​</a></h4><table tabindex="0"><thead><tr><th>统计周期</th><th>马萨诸塞投资信托</th><th>投资者股票基金</th><th>雷曼公司</th><th>大陆三角公司</th><th>道指</th><th>有限合伙人收益率</th></tr></thead><tbody><tr><td>1957年</td><td>-11.4%</td><td>-12.4%</td><td>-11.4%</td><td>-2.4%</td><td>-8.4%</td><td>9.3%</td></tr><tr><td>1957-1958年</td><td>26.4%</td><td>29.2%</td><td>24.7%</td><td>30.0%</td><td>26.9%</td><td>44.5%</td></tr><tr><td>1957-1959年</td><td>37.8%</td><td>42.5%</td><td>34.8%</td><td>40.9%</td><td>52.3%</td><td>74.7%</td></tr><tr><td>1957-1960年</td><td>36.4%</td><td>41.6%</td><td>38.2%</td><td>44.8%</td><td>42.9%</td><td>107.2%</td></tr><tr><td>1957-1961年</td><td>71.4%</td><td>76.9%</td><td>70.8%</td><td>77.4%</td><td>74.9%</td><td>181.6%</td></tr><tr><td>1957年-1962年6月30日</td><td>31.9%</td><td>32.0%</td><td>暂无数据</td><td>暂无数据</td><td>37.0%</td><td>160.5%</td></tr></tbody></table>',48)])])}const _=d(h,[["render",o]]);export{c as __pageData,_ as default};
